"""Solver-agnostic inverse modeling utilities.

Provides the abstract solver base class, design variable parameterizations,
objective functionals, iteration reporters, and misfit loggers used by
both the SSA and Blatter inverse solvers.
"""

import PISM
import math

from PISM.logging import logMessage


# ============================================================================
# Abstract solver base class
# ============================================================================

class InvSolver(object):
    """Abstract base class for inverse problem solvers.

    Subclasses must override all methods that raise :exc:`NotImplementedError`.
    """

    def __init__(self, run, method):
        """Initialize the inverse solver.

        Parameters
        ----------
        run : SSARun or BlatterForwardRun
            The forward problem setup.
        method : str
            Algorithm name (e.g. ``'tikhonov_lmvm'``).
        """
        self.run = run
        self.config = run.config
        self.method = method

    def solveForward(self, zeta, out=None):
        r"""Solve the forward problem for a given :math:`\zeta`.

        Must be overridden by subclasses.

        Parameters
        ----------
        zeta : Array
            Parameterized design variable.
        out : Array, optional
            Storage for the result.

        Returns
        -------
        Array
            The computed velocity.
        """
        raise NotImplementedError()

    def addIterationListener(self, listener):
        """Add a listener called after each iteration. Must be overridden."""
        raise NotImplementedError()

    def addDesignUpdateListener(self, listener):
        """Add a listener called after each design variable update. Must be overridden."""
        raise NotImplementedError()

    def solveInverse(self, zeta0, u_obs, zeta_inv):
        r"""Execute the inversion algorithm. Must be overridden.

        Parameters
        ----------
        zeta0 : Array
            Prior guess for :math:`\zeta`.
        u_obs : array.Vector
            Observed surface velocities.
        zeta_inv : Array
            Starting value of :math:`\zeta`.

        Returns
        -------
        TerminationReason
            Why the solver stopped.
        """
        raise NotImplementedError()

    def inverseSolution(self):
        """Return ``(zeta, u)`` at the end of inversion. Must be overridden."""
        raise NotImplementedError()


# Backwards-compatible alias
InvSSASolver = InvSolver


# ============================================================================
# Design variable parameterization
# ============================================================================

design_param_types = {"ident": PISM.IPDesignVariableParamIdent,
                      "square": PISM.IPDesignVariableParamSquare,
                      "exp": PISM.IPDesignVariableParamExp,
                      "trunc": PISM.IPDesignVariableParamTruncatedIdent}


def createDesignVariableParam(config, design_var_name, param_name=None):
    """Create a design variable parameterization from config.

    Parameters
    ----------
    config : Config
        PISM configuration object.
    design_var_name : str
        Design variable name (e.g. ``'tauc'``).
    param_name : str, optional
        Parameterization type. If ``None``, read from ``inverse.design.param``.

    Returns
    -------
    IPDesignVariableParameterization
        A configured parameterization instance.
    """
    if param_name is None:
        param_name = config.get_string("inverse.design.param")
    design_param = design_param_types[param_name]()
    design_param.set_scales(config, design_var_name)
    return design_param


# ============================================================================
# Objective functionals
# ============================================================================

def createMeanSquareMisfitFunctional(grid, vecs):
    """Create a mean-square misfit functional.

    Parameters
    ----------
    grid : Grid
        The computation grid.
    vecs : ModelVecs
        Model vectors, optionally containing ``'vel_misfit_weight'``.

    Returns
    -------
    IPMeanSquareFunctional2V
        A mean-square misfit functional.
    """
    misfit_weight = None
    if vecs.has('vel_misfit_weight'):
        misfit_weight = vecs.vel_misfit_weight

    velocity_scale = grid.ctx().config().get_number(
        "inverse.stress_balance.velocity_scale", "m/second")
    stateFunctional = PISM.IPMeanSquareFunctional2V(grid, misfit_weight)
    stateFunctional.normalize(velocity_scale)
    return stateFunctional


def createHilbertDesignFunctional(grid, vecs, useGroundedIceOnly, run=None):
    """Create an H1 Sobolev norm design variable functional.

    Parameters
    ----------
    grid : Grid
        The computation grid.
    vecs : ModelVecs
        Model vectors.
    useGroundedIceOnly : bool
        If ``True``, restrict to grounded ice.

    Returns
    -------
    IP_H1NormFunctional2S or IPGroundedIceH1NormFunctional2S
        The design variable functional.
    """
    cL2 = grid.ctx().config().get_number("inverse.design.cL2")
    cH1 = grid.ctx().config().get_number("inverse.design.cH1")

    area = 4 * grid.Lx() * grid.Ly()
    length_scale = grid.ctx().config().get_number(
        "inverse.stress_balance.length_scale")
    cL2 /= area
    cH1 /= area
    cH1 *= (length_scale * length_scale)

    zeta_fixed_mask = None
    if vecs.has('zeta_fixed_mask'):
        zeta_fixed_mask = vecs.zeta_fixed_mask

    if useGroundedIceOnly:
        # IPGroundedIceH1NormFunctional2S requires a CellType1 reference.
        # vecs.mask returns a generic Array from the Vars container,
        # losing the CellType2 type. Access geometry.cell_type directly.
        if run is not None and hasattr(run, 'geometry'):
            cell_type = run.geometry.cell_type
        else:
            cell_type = vecs.mask
        designFunctional = PISM.IPGroundedIceH1NormFunctional2S(
            grid, cL2, cH1, cell_type, zeta_fixed_mask)
    else:
        designFunctional = PISM.IP_H1NormFunctional2S(
            grid, cL2, cH1, zeta_fixed_mask)

    return designFunctional


def createGradientFunctionals(run):
    """Create functionals for gradient-based inversions.

    Parameters
    ----------
    run : SSAForwardRun or BlatterForwardRun
        The forward problem setup.

    Returns
    -------
    tuple of IP_Functional
        ``(designFunctional, stateFunctional)``.
    """
    vecs = run.modeldata.vecs
    grid = run.grid

    useGroundedIceOnly = PISM.OptionBool(
        "-inv_ssa_grounded_ice_tauc",
        "Computed norms for tau_c only on elements with all grounded ice.")

    misfit_type = grid.ctx().config().get_string("inverse.state_func")
    if misfit_type != 'meansquare':
        inv_method = grid.ctx().config().get_string(
            "inverse.stress_balance.method")
        raise Exception(
            "'-inv_state_func %s' is not supported with '-inv_method %s'.\n"
            "Use '-inv_state_func meansquare' instead"
            % (misfit_type, inv_method))

    design_functional = grid.ctx().config().get_string("inverse.design.func")
    if design_functional != "sobolevH1":
        inv_method = grid.ctx().config().get_string(
            "inverse.stress_balance.method")
        raise Exception(
            "'-inv_design_func %s' is not supported with '-inv_method %s'.\n"
            "Use '-inv_design_func sobolevH1' instead"
            % (design_functional, inv_method))

    designFunctional = createHilbertDesignFunctional(
        grid, vecs, useGroundedIceOnly, run=run)
    stateFunctional = createMeanSquareMisfitFunctional(grid, vecs)

    return (designFunctional, stateFunctional)


def createTikhonovFunctionals(run):
    """Create functionals for Tikhonov-based inversions.

    Parameters
    ----------
    run : SSAForwardRun or BlatterForwardRun
        The forward problem setup.

    Returns
    -------
    tuple of IP_Functional
        ``(designFunctional, stateFunctional)``.
    """
    vecs = run.modeldata.vecs
    grid = run.grid

    ctx = grid.ctx()
    config = ctx.config()
    sys = ctx.unit_system()

    useGroundedIceOnly = PISM.OptionBool(
        "-inv_ssa_grounded_ice_tauc",
        "Computed norms for tau_c only on elements with all grounded ice.")

    misfit_type = config.get_string("inverse.state_func")
    if misfit_type == "meansquare":
        stateFunctional = createMeanSquareMisfitFunctional(grid, vecs)
    elif misfit_type == "log_ratio":
        vel_observed = (vecs.vel_observed if vecs.has('vel_observed')
                        else vecs.vel_ssa_observed)
        scale = config.get_number("inverse.log_ratio_scale")
        velocity_eps = config.get_number(
            "inverse.stress_balance.velocity_eps", "m/second")
        misfit_weight = None
        if vecs.has('vel_misfit_weight'):
            misfit_weight = vecs.vel_misfit_weight
        stateFunctional = PISM.IPLogRatioFunctional(
            grid, vel_observed, velocity_eps, misfit_weight)
        stateFunctional.normalize(scale)
    elif misfit_type == "log_relative":
        vel_observed = (vecs.vel_observed if vecs.has('vel_observed')
                        else vecs.vel_ssa_observed)
        velocity_scale = config.get_number(
            "inverse.stress_balance.velocity_scale", "m/second")
        velocity_eps = config.get_number(
            "inverse.stress_balance.velocity_eps", "m/second")
        misfit_weight = None
        if vecs.has('vel_misfit_weight'):
            misfit_weight = vecs.vel_misfit_weight
        stateFunctional = PISM.IPLogRelativeFunctional(
            grid, vel_observed, velocity_eps, misfit_weight)
        stateFunctional.normalize(velocity_scale)
    else:
        raise RuntimeError(
            "Unknown inv_state_func '%s'; unable to construct solver."
            % misfit_type)

    design_functional = config.get_string("inverse.design.func")
    if design_functional == "sobolevH1":
        designFunctional = createHilbertDesignFunctional(
            grid, vecs, useGroundedIceOnly, run=run)
    elif design_functional == "tv":
        area = 4 * grid.Lx() * grid.Ly()
        velocity_scale = config.get_number(
            "inverse.stress_balance.velocity_scale", "m/second")
        length_scale = config.get_number(
            "inverse.stress_balance.length_scale")
        lebesgue_exponent = config.get_number(
            "inverse.stress_balance.tv_exponent")
        cTV = 1 / area
        cTV *= (length_scale) ** (lebesgue_exponent)

        zeta_fixed_mask = None
        if vecs.has('zeta_fixed_mask'):
            zeta_fixed_mask = vecs.zeta_fixed_mask

        strain_rate_eps = PISM.OptionReal(
            sys, "-inv_ssa_tv_eps",
            "regularization constant for 'total variation' functional",
            "1 / m", 0.0)
        if not strain_rate_eps.is_set():
            schoofLen = config.get_number(
                "flow_law.Schoof_regularizing_length", "m")
            strain_rate_eps = 1 / schoofLen
        else:
            strain_rate_eps = strain_rate_eps.value()

        designFunctional = PISM.IPTotalVariationFunctional2S(
            grid, cTV, lebesgue_exponent, strain_rate_eps, zeta_fixed_mask)
    else:
        raise Exception(
            "Unknown inv_design_func '%s'; unable to construct solver."
            % design_functional)

    return (designFunctional, stateFunctional)


# ============================================================================
# Iteration listeners and reporters
# ============================================================================

def printIteration(solver, it, data):
    """Print a header for an iteration report.

    Parameters
    ----------
    solver : InvSolver
        The inverse solver instance.
    it : int
        The iteration number.
    data : dict
        Iteration data.
    """
    logMessage("----------------------------------------------------------\n")
    logMessage("Iteration %d\n" % it)


def printTikhonovProgress(solver, it, data):
    """Report on the progress of a Tikhonov iteration.

    Parameters
    ----------
    solver : InvSolver
        The inverse solver instance.
    it : int
        The iteration number.
    data : dict
        Iteration data containing ``tikhonov_penalty``, ``JState``,
        ``JDesign``, and optionally ``grad_JTikhonov`` or ``constraints``.
    """
    eta = data.tikhonov_penalty
    stateVal = data.JState
    designVal = data.JDesign
    sWeight = 1
    dWeight = 1.0 / eta

    norm_type = PISM.PETSc.NormType.NORM_2

    logMessage("design objective %.8g; weighted %.8g\n"
               % (designVal, designVal * dWeight))
    if 'grad_JTikhonov' in data:
        logMessage("gradient: design %.8g state %.8g sum %.8g\n"
                   % (data.grad_JDesign.norm(norm_type)[0] * dWeight,
                      data.grad_JState.norm(norm_type)[0] * sWeight,
                      data.grad_JTikhonov.norm(norm_type)[0]))
    else:
        logMessage("gradient: design %.8g state %.8g; constraints: %.8g\n"
                   % (data.grad_JDesign.norm(norm_type)[0] * dWeight,
                      data.grad_JState.norm(norm_type)[0] * sWeight,
                      data.constraints.norm(norm_type)[0]))
    logMessage("tikhonov functional: %.8g\n"
               % (stateVal * sWeight + designVal * dWeight))


class RMSMisfitReporter(object):
    """Iteration listener that reports RMS misfit."""

    def __init__(self):
        self.J = None

    def __call__(self, solver, it, data):
        """Compute and log the diagnostic RMS misfit."""
        grid = solver.run.grid

        if self.J is None:
            vecs = solver.run.modeldata.vecs
            self.J = createMeanSquareMisfitFunctional(grid, vecs)

        Jmisfit = self.J.valueAt(data.residual)
        rms_misfit = (math.sqrt(Jmisfit)
                      * grid.ctx().config().get_number(
                          "inverse.stress_balance.velocity_scale"))

        PISM.logging.logMessage(
            "Diagnostic RMS Misfit: %0.8g (m/a)\n" % rms_misfit)


class MisfitLogger(object):
    """Iteration listener that logs and saves misfit history."""

    def __init__(self):
        self.misfit_history = []
        self.misfit_type = None

    def __call__(self, solver, it, data):
        """Log the misfit value for this iteration."""
        grid = solver.run.grid

        if self.misfit_type is None:
            self.misfit_type = grid.ctx().config().get_string(
                "inverse.state_func")

        method = solver.method
        if method == 'ign' or method == 'sd' or method == 'nlcg':
            import PISM.invert.sipletools
            fp = solver.forward_problem
            r = PISM.invert.sipletools.PISMLocalVector(data.residual)
            Jmisfit = fp.rangeIP(r, r)
        elif 'JState' in data:
            Jmisfit = data.JState
        else:
            raise RuntimeError(
                "Unable to report misfits for inversion method: %s" % method)

        if self.misfit_type == "meansquare":
            velScale = grid.ctx().config().get_number(
                "inverse.stress_balance.velocity_scale")
            rms_misfit = math.sqrt(Jmisfit) * velScale
            logMessage("Misfit: sqrt(J_misfit) = %.8g (m/a)\n" % rms_misfit)
            self.misfit_history.append(rms_misfit)
        else:
            logMessage("Misfit: J_misfit = %.8g (dimensionless)\n" % Jmisfit)
            self.misfit_history.append(Jmisfit)

    def write(self, output_filename):
        """Save misfit history as ``inv_misfit`` to a NetCDF file.

        Parameters
        ----------
        output_filename : str
            Path to the output file.
        """
        N = len(self.misfit_history)

        ds = PISM.File(PISM.Context().com, output_filename,
                       PISM.PISM_NETCDF3, PISM.PISM_READWRITE)

        ds.redef()
        ds.define_dimension('inv_iter', N)
        ds.define_variable("inv_misfit", PISM.PISM_DOUBLE, ["inv_iter"])
        if self.misfit_type == "meansquare":
            ds.write_attribute("inv_misfit", "units", "m/a")
        ds.write_variable("inv_misfit", [0], [N], self.misfit_history)
        ds.close()


class ZetaSaver(object):
    r"""Iteration listener that saves :math:`\zeta` at each iteration."""

    def __init__(self, output_filename):
        """Initialize.

        Parameters
        ----------
        output_filename : str
            Path to the output file.
        """
        self.output_filename = output_filename

    def __call__(self, solver, count, data):
        """Save the current zeta to the output file."""
        zeta = data.zeta
        zeta.metadata().set_name('zeta_inv')
        zeta.metadata().set_string(
            'long_name',
            'last iteration of parameterized basal yield stress '
            'computed by inversion')
        zeta.write(self.output_filename)
